@startuml
!theme plain

class "PersonaFactoryMethod" as PersonaFactoryMethod {
  [A]
  crearPersona( id )
}

class "PersonaFactory" as PersonaFactory {
  [C]
}

class "Cliente" as Cliente {
  [C]
}

class "Mecanico" as Mecanico {
  [C]
}

class "Oficinista" as Oficinista {
  [C]
}

class "Persona" as Persona {
  [A]
}

class "Empleado" as Empleado {
  [A]
}

PersonaFactoryMethod <|-- PersonaFactory
PersonaFactory ..> Cliente : «instancia»
PersonaFactory ..> Mecanico : «instancia»
PersonaFactory ..> Oficinista : «instancia»
Cliente --|> Persona
Mecanico --|> Empleado
Oficinista --|> Empleado
Empleado --|> Persona

@enduml
